/** Up to two initials from the local part of an email (before @), or "?". */
export function getInitialsFromEmail(email: string): string {
  const local = email.trim().split("@")[0] ?? "";
  if (!local) {
    return "?";
  }
  const asName = local.replaceAll(/[._-]+/g, " ");
  return getTenantInitials(asName);
}

